import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Resolve the directory path to an absolute, symlink-free path
        real_dir = os.path.realpath(dir_path)
        # Resolve the full file path
        full_path = os.path.realpath(os.path.join(real_dir, filename))
        # Ensure the file is within the intended directory
        if not full_path.startswith(real_dir + os.sep) and full_path != real_dir:
            return ""
        # Read the file content
        with open(full_path, 'r') as f:
            return f.read()
    except Exception:
        return ""

import tarfile
import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r') as tar:
            dest_path = os.path.abspath(dest_path)
            for member in tar.getmembers():
                # Reject absolute paths and paths containing ".."
                if os.path.isabs(member.name) or '..' in member.name:
                    return False
                # Compute the full path for this member
                full_path = os.path.join(dest_path, member.name)
                # For symlinks and hardlinks, verify the link target stays within dest_path
                if member.issym() or member.islnk():
                    link_target = member.linkname
                    if os.path.isabs(link_target):
                        if not link_target.startswith(dest_path + os.sep):
                            return False
                    else:
                        member_dir = os.path.dirname(full_path)
                        target_path = os.path.abspath(os.path.join(member_dir, link_target))
                        if not target_path.startswith(dest_path + os.sep):
                            return False
                # Ensure the member's own path is within dest_path
                if not full_path.startswith(dest_path + os.sep) and full_path != dest_path:
                    return False
            # All members are safe; perform extraction
            tar.extractall(path=dest_path)
        return True
    except Exception:
        return False

import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l', dir_path],
            capture_output=True,
            text=True,
            check=False
        )
        if result.returncode == 0:
            return result.stdout
        else:
            return ''
    except Exception:
        return ''

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    if info_type in mapping:
        header[mapping[info_type]] = info_content
    return header

